SELECT p.project_id, p.project_key, p.project_name, p.project_type_code, p.project_status, p.start_date, p.end_date, p.owner_user_id, COUNT(DISTINCT t.task_id) AS task_count, COUNT(DISTINCT m.milestone_id) AS milestone_count FROM schedule_project p LEFT JOIN schedule_task t ON t.project_id = p.project_id LEFT JOIN schedule_milestone m ON m.project_id = p.project_id
AND ( p.project_name ILIKE CONCAT('%', #{keyword}, '%') OR p.project_key ILIKE CONCAT('%', #{keyword}, '%') )
AND p.project_status = #{project_status}
AND p.owner_user_id = #{owner_user_id}
GROUP BY p.project_id, p.project_key, p.project_name, p.project_type_code, p.project_status, p.start_date, p.end_date, p.owner_user_id ORDER BY p.project_id DESC

SELECT COUNT(1)
FROM schedule_project
WHERE project_key = #{project_key}

    AND project_id != #{project_id}
